#include <stdio.h>
#include <stdlib.h>

#define MAX 100

typedef struct Node {
 int vertex;
 struct Node* next;
} Node;

typedef struct {
 int n;
 Node* adjList[MAX];
 int visited[MAX];
} Graph;

// Queue structure for BFS
typedef struct {
 int data[MAX];
 int front;
 int rear;
} Queue;

// Store spanning tree edges
int treeEdgesU[MAX], treeEdgesV[MAX];
int edgeCount = 0;

Node* createNode(int v) {
 Node* newNode = (Node*)malloc(sizeof(Node));
 newNode->vertex = v;
 newNode->next = NULL;
 return newNode;
}

void initGraph(Graph* g, int n) {
 g->n = n;
 for (int i = 0; i < n; i++) {
 g->adjList[i] = NULL;
 g->visited[i] = 0;
 }
}

void addEdge(Graph* g, int u, int v) {
 // Add edge u -> v
 Node* newNode = createNode(v);
 newNode->next = g->adjList[u];
 g->adjList[u] = newNode;

 // Add edge v -> u (undirected)
 newNode = createNode(u);
 newNode->next = g->adjList[v];
 g->adjList[v] = newNode;
}

// Queue operations
void initQueue(Queue* q) {
 q->front = 0;
 q->rear = -1;
}

int isEmpty(Queue* q) {
 return q->rear < q->front;
}

void enqueue(Queue* q, int value) {
 q->data[++q->rear] = value;
}

int dequeue(Queue* q) {
 return q->data[q->front++];
}

void BFS_SpanningTree(Graph* g, int start) {
 Queue q;
 initQueue(&q);

 // Mark start vertex as visited and enqueue it
 g->visited[start] = 1;
 enqueue(&q, start);

 printf("BFS Spanning Tree construction from vertex %d:\n", start);

 while (!isEmpty(&q)) {
 int v = dequeue(&q);
 Node* temp = g->adjList[v];

 while (temp) {
 int neighbor = temp->vertex;

 if (!g->visited[neighbor]) {
 // This is a tree edge - discovered new vertex
 g->visited[neighbor] = 1;
 treeEdgesU[edgeCount] = v;
 treeEdgesV[edgeCount] = neighbor;
 edgeCount++;

 printf(" Tree edge: (%d, %d)\n", v, neighbor);
 enqueue(&q, neighbor);
 }
 temp = temp->next;
 }
 }
}

int isConnected(Graph* g) {
 // Reset visited array
 for (int i = 0; i < g->n; i++)
 g->visited[i] = 0;

 Queue q;
 initQueue(&q);

 // Start BFS from vertex 0
 g->visited[0] = 1;
 enqueue(&q, 0);
 int count = 0;

 while (!isEmpty(&q)) {
 int v = dequeue(&q);
 count++;

 Node* temp = g->adjList[v];
 while (temp) {
 if (!g->visited[temp->vertex]) {
 g->visited[temp->vertex] = 1;
 enqueue(&q, temp->vertex);
 }
 temp = temp->next;
 }
 }

 return count == g->n;
}

int main() {
 Graph g;

 // Create graph with 4 vertices
 //
 // 0 --- 1
 // | \ |
 // | \ |
 // | \|
 // 2 --- 3
 //
 initGraph(&g, 4);
 addEdge(&g, 0, 1);
 addEdge(&g, 0, 2);
 addEdge(&g, 1, 2);
 addEdge(&g, 1, 3);
 addEdge(&g, 2, 3);

 printf("=== BFS Spanning Tree Demo ===\n\n");

 // Check connectivity
 if (isConnected(&g)) {
 printf("Graph is connected.\n\n");
 } else {
 printf("Graph is not connected.\n\n");
 }

 // Reset visited for BFS
 for (int i = 0; i < g.n; i++)
 g.visited[i] = 0;

 // Build BFS spanning tree
 BFS_SpanningTree(&g, 0);

 printf("\nSpanning tree edges:");
 for (int i = 0; i < edgeCount; i++)
 printf(" (%d,%d)", treeEdgesU[i], treeEdgesV[i]);

 printf("\nTotal edges: %d (expected: %d)\n", edgeCount, g.n - 1);

 // Compare with DFS (from topic)
 printf("\n=== Note ===\n");
 printf("BFS tree is SHORT and WIDE (levels)\n");
 printf("DFS tree (from topic) is DEEP and NARROW\n");

 return 0;
}
